import os
from contextlib import ExitStack
from unittest.mock import patch


def pytest_sessionstart(session):
    """Set database URLs before any test runs."""
    session._env_stack = ExitStack()
    session._env_stack.enter_context(
        patch.dict(
            os.environ,
            {
                "DATABASE_URL": "sqlite+aiosqlite:///file:testdb?mode=memory&cache=shared",
                "SYNC_DATABASE_URL": "sqlite:///file:testdb?mode=memory&cache=shared",
            },
        )
    )


def pytest_sessionfinish(session):
    """Restore environment variables after all tests."""
    stack = getattr(session, "_env_stack", None)
    if stack:
        stack.close()
